import{_ as e,o as i,c as r,ai as n,ao as t,ap as l,aq as o,ar as s,as as p,at as h}from"./chunks/framework.BAN1Dymk.js";const P=JSON.parse('{"title":"GAMES101-Shading","description":"着色","frontmatter":{"title":"GAMES101-Shading","date":"2026-04-12T00:00:00.000Z","description":"着色"},"headers":[],"relativePath":"posts/GAMES101-Shading.md","filePath":"posts/GAMES101-Shading.md"}'),d={name:"posts/GAMES101-Shading.md"};function c(g,a,m,u,f,b){return i(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="着色" tabindex="-1">着色 <a class="header-anchor" href="#着色" aria-label="Permalink to “着色”">​</a></h1><h2 id="definition" tabindex="-1">Definition <a class="header-anchor" href="#definition" aria-label="Permalink to “Definition”">​</a></h2><blockquote><p>shading:</p></blockquote><blockquote><p>The darkening or coloring of an illustration or diagram with parallel lines or a block of color</p></blockquote><p>在图形学中，可以理解为对物体应用不同的材质。</p><h2 id="blinn-phong-反射模型" tabindex="-1">Blinn-Phong 反射模型 <a class="header-anchor" href="#blinn-phong-反射模型" aria-label="Permalink to “Blinn-Phong 反射模型”">​</a></h2><p>着色时的输入参数：</p><ul><li>Viewer direction，视线方向</li><li>Surface normal，表面法线方向</li><li>Light direction，光线方向</li><li>Surface parameters，物体表面的参数，如颜色、粗糙度</li></ul><p>着色时，对于物体表面的着色是局部的，意思是不考虑自身以外的着色。比如不考虑物体在光照下投射的阴影。</p><h3 id="diffuse-reflection-漫反射" tabindex="-1">Diffuse Reflection 漫反射 <a class="header-anchor" href="#diffuse-reflection-漫反射" aria-label="Permalink to “Diffuse Reflection 漫反射”">​</a></h3><p>将光线在物体表面均匀地向各个方向散射。反射光线的强度与物体与光线的夹角有关，因为单位面积接受到的能量不同。</p><p><img src="'+t+'" alt="alt text"></p><p>因为漫反射是均匀地反射射入光线，所以不管在什么地方观察，观察到的着色效果应该是一样的。</p><h3 id="specular-高光" tabindex="-1">Specular 高光 <a class="header-anchor" href="#specular-高光" aria-label="Permalink to “Specular 高光”">​</a></h3><p>反射方向接近于镜面反射方向。在判断是否产生高光时，计算光线入射向量和视线向量的半程向量，即取角平分线方向，只需要检查半程向量和法线向量是否足够接近。</p><p><img src="'+l+'" alt="alt text"></p><p>公式中的指数p意在控制高光的大小，对于点乘，cos变换的容忍度过高，比如半程向量和法线向量偏移45°时，和完全重合计算得出的值差别并不大，导致高光的面积可能过大。因此需要进行指数运算，增强计算结果的变化率。</p><h3 id="ambient-term-环境光" tabindex="-1">Ambient Term 环境光 <a class="header-anchor" href="#ambient-term-环境光" aria-label="Permalink to “Ambient Term 环境光”">​</a></h3><p>为物体添加一个常数光照，不受外界影响，为了避免有的地方是完全黑色的。Blinn-Phong的环境光是对实际情况的简化，仅模拟最简单的环境光。</p><p><img src="'+o+'" alt="alt text"></p><p>将三种光照效果合成，就是最终的着色效果。</p><h2 id="shading-frequencies" tabindex="-1">Shading Frequencies <a class="header-anchor" href="#shading-frequencies" aria-label="Permalink to “Shading Frequencies”">​</a></h2><p>着色频率，决定每次着色区域的大小。</p><h3 id="flat-shading" tabindex="-1">Flat Shading <a class="header-anchor" href="#flat-shading" aria-label="Permalink to “Flat Shading”">​</a></h3><p>对每个三角形着色。同一个三角形中的所有像素点着色效果相同。</p><p><img src="'+s+'" alt="alt text"></p><h3 id="gouraud-shading" tabindex="-1">Gouraud Shading <a class="header-anchor" href="#gouraud-shading" aria-label="Permalink to “Gouraud Shading”">​</a></h3><p>对每个三角形的顶点着色，三角形内部的像素着色使用顶点的着色插值着色。</p><p><img src="'+p+'" alt="alt text"></p><h3 id="phong-shading" tabindex="-1">Phong Shading <a class="header-anchor" href="#phong-shading" aria-label="Permalink to “Phong Shading”">​</a></h3><p>只传递顶点的法线向量，对每个像素插值得到像素点的法线向量，再逐像素计算着色。</p><p><img src="'+h+'" alt="alt text"></p><blockquote><p>怎样得到顶点的法线向量？</p></blockquote><blockquote><p>根据和顶点相连的几个三角形，根据三角形的法线向量加权平均计算顶点的法线向量。</p></blockquote><h2 id="real-time-rendering-pipeline-实时渲染管线" tabindex="-1">Real-Time Rendering Pipeline 实时渲染管线 <a class="header-anchor" href="#real-time-rendering-pipeline-实时渲染管线" aria-label="Permalink to “Real-Time Rendering Pipeline 实时渲染管线”">​</a></h2><p>输入：原始3D空间</p><ul><li>Vertex Processing:将原始3D空间转换为屏幕视口空间</li><li>Triangle Processing:将屏幕空间的顶点转换为三角形</li><li>Rasterization:将需要绘制的三角形光栅化为像素点</li><li>Fragment Processing:为像素点着色</li><li>Framebuffer Operations:将着色后的像素点显示在屏幕上</li></ul><p>对于不同的着色算法，着色发生的流程也有所不同。如果采用Gouraud Shading顶点着色，则着色发生在Vertex Processing(计算颜色)、Rasterization(进行颜色插值)和Fragment Processing(使用插值颜色)；Phong着色发生在Vertex Processing(传递顶点法线向量)、Rasterization(进行重心坐标插值，插值生成法线向量)和Fragment Processing(计算并使用颜色)</p><h2 id="texture-mapping-纹理映射" tabindex="-1">Texture Mapping 纹理映射 <a class="header-anchor" href="#texture-mapping-纹理映射" aria-label="Permalink to “Texture Mapping 纹理映射”">​</a></h2><p>为了使3D物体在着色时显示特定的纹理，需要对2D的纹理进行纹理映射。在3D物体上先进行纹理的绘制，储存时再展开为2D图像，再次渲染时则将展开的2D图像纹理贴回3D物体，实现纹理映射。</p><p>为了保证纹理能够贴合物体的对应位置，使用uv坐标系规定一个坐标，一般坐标范围定义为[0-1]的浮点数。在光栅化时，GPU对三角形内部的像素进行插值UV坐标，从而确定哪个像素采样纹理的哪个部分。</p><p>一般来讲，UV坐标和顶点坐标并行传递，不受各种矩阵变换的影响，在光栅化生成片元时会进行透视矫正插值，防止纹理变形。</p>',42)])])}const S=e(d,[["render",c]]);export{P as __pageData,S as default};
